draw(surface(C--O--D--cycle),red+white,nolight);
draw(B--C--D);
draw(B--A--D,dashed);
draw(EE--F--G--H--EE);
draw(A--EE,dashed);
draw(B--F);
draw(C--G);
draw(D--H);
draw(A--O--C,dashed);
