fill((0,10)..(-10,0)--(10,0)..cycle,black);
fill((-10,0)--(-5,8.7)--(5,8.7)--(10,0)--cycle,white);
draw((0,10)..(-10,0)--(10,0)..cycle);
draw((-10,0)--(-5,8.7)--(5,8.7)--(10,0)--cycle);
draw((-5,8.7)--(0,0)--(5,8.7));
draw(anglemark((-5,8.7),(0,0),(-10,0),30));
draw(anglemark((5,8.7),(0,0),(-5,8.7),35));
draw(anglemark((10,0),(0,0),(5,8.7),30));
[/asy]

We have  \begin{align*}
\frac{12}{x \cdot x} \cdot \frac{x^4}{14x}\cdot \frac{35}{3x} &=
\frac{12 \cdot x^4 \cdot 35}{x^2\cdot 14x \cdot 3x}\\& = \frac{(4 \cdot 3) \cdot (5 \cdot 7) \cdot x^4}{(3 \cdot 2 \cdot 7)(x^2 \cdot x \cdot x)}\\
&= \frac{2\cdot 2 \cdot 3 \cdot 5 \cdot 7}{2 \cdot 3 \cdot 7}\cdot\frac{x^4}{x^{4}}\\
